      var wg = ctx.createLinearGradient(0, L, 0, L + 220);
      wg.addColorStop(0, 'rgba(0,0,0,0)'); wg.addColorStop(1, DEEP);
      ctx.fillStyle = wg; topPath(); ctx.fill();
