    ctx.fillStyle = POUR;
    for (var p = 0; p < pourStreams.length; p++) {
      var ps = pourStreams[p], by = surfYAt(ps.x) - 2;
      for (var y = ps.y; y < by; y += 6) { var wob = Math.sin(y * 0.12 + frame * 0.5) * 1.8; ctx.fillRect(ps.x - 4 + wob, y, 8, 6); }
    }
