    var z = (window.RG && RG._zoom != null) ? RG._zoom : 1;
    var pvx = (window.RG && RG._zoomPivot) ? RG._zoomPivot.x : W_() / 2, pvy = (window.RG && RG._zoomPivot) ? RG._zoomPivot.y : H_() / 2;
