    hold: function (frac, above) { var h = hole(); if (!h) return; var wx = h.teeX + (h.cupX - h.teeX) * frac; heldPour = { x: wx, y: terrainYAt(wx) - (above == null ? 90 : above) }; },
    release: function () { heldPour = null; },
    clear: clearFluid,
    blocks: function () { return blocks; },
